/**
 * runtime_main.cpp — ST2C++ Flat Runtime (generic desktop)
 *
 * Responsibilities:
 *   1. Call configureRuntime() (generated by gen_config.py)
 *   2. Run scheduling loop + diagnostics
 *
 * Platform-agnostic: no GPIO, no EtherCAT.
 * Uses std::chrono for timing (low precision, dev/test only).
 */
#include "rt_runtime.h"
#include "rt_plc.h"

#include <cstdio>
#include <cstring>
#include <cmath>
#include <algorithm>
#include <csignal>

#include "core/platform.h"

#ifdef ENABLE_DEBUG
#include "debug/debug_if.h"
#include "debug_tcp_server.h"
static rt_plc::DebugEngine debugEngine;

namespace rt_plc {
extern const DebugVar  st2c_debug_vars[];
extern const uint32_t  st2c_debug_var_count;
extern const uint8_t   st2c_build_id[16];
}
#endif

using namespace rt_plc;

static volatile bool running = true;
static void signalHandler(int) { running = false; }

// ═══ 配置 ═══
static int64_t   cycleUs       = 1000;
static int       diagIntervalS = 5;
static bool      jitterOnly    = false;

static Scheduler sched;
static CompositeTCI compositeTCI;

// ═══ 抖动统计 ═══
static struct {
    int64_t intervalUs;
    int64_t prevUs;
    int64_t minJitter, maxJitter;
    int64_t sumJitter;
    int64_t sumSquareJitter;
    uint64_t count;
    bool ready;
} jitter = {1000, 0, 999999, -999999, 0, 0, 0, false};

static void jitterReset(int64_t us) {
    jitter.intervalUs = us;
    jitter.prevUs = 0; jitter.minJitter = 999999; jitter.maxJitter = -999999;
    jitter.sumJitter = 0; jitter.sumSquareJitter = 0; jitter.count = 0; jitter.ready = false;
}

static void jitterSample(int64_t now) {
    if (!jitter.ready) { jitter.prevUs = now; jitter.ready = true; return; }
    int64_t actual = now - jitter.prevUs;
    int64_t jit = actual - jitter.intervalUs;
    jitter.prevUs = now;
    jitter.minJitter = std::min(jitter.minJitter, jit);
    jitter.maxJitter = std::max(jitter.maxJitter, jit);
    jitter.sumJitter += jit;
    jitter.sumSquareJitter += jit * jit;
    jitter.count++;
}

static void printJitterStats() {
    if (jitter.count > 0) {
        int64_t avg = jitter.sumJitter / (int64_t)jitter.count;
        double variance = jitter.count > 1
            ? (double)jitter.sumSquareJitter / jitter.count - (double)avg * avg
            : 0;
        printf("\n=== Jitter Stats ===\n");
        printf("  Target  : %lld us\n", (long long)jitter.intervalUs);
        printf("  Samples : %llu\n", (unsigned long long)jitter.count);
        printf("  Min     : %lld us\n", (long long)jitter.minJitter);
        printf("  Max     : %lld us\n", (long long)jitter.maxJitter);
        printf("  Avg     : %lld us\n", (long long)avg);
        printf("  StdDev  : %lld us\n", (long long)(variance > 0 ? (int64_t)std::sqrt(variance) : 0));
    }
}

// ═══ PLC ═══
extern void configureRuntime(Scheduler& sched, CompositeTCI& tci);

static void plcInit() {
    configureRuntime(sched, compositeTCI);
    if (cycleUs != sched.baseCycleTime)
        sched.setBaseCycle(T_us(cycleUs));
    sched.start(StartupMode::COLD);
    platform::logInfo("PLC Runtime: cycle=%lldus\n", (long long)cycleUs);
}

static void plcTick() {
    sched.tick();
}

// ═══ 主函数 ═══
int main(int argc, char* argv[]) {
    setbuf(stdout, NULL);
    RT_LOG_INFO("=== ST2C++ Flat Runtime ===\n\n");

    for (int i = 1; i < argc; i++) {
        if (argv[i][0] != '-') continue;
        if (strcmp(argv[i], "--cycle-us") == 0 && i + 1 < argc) {
            cycleUs = atol(argv[++i]);
        } else if (strcmp(argv[i], "--diag-interval") == 0 && i + 1 < argc) {
            diagIntervalS = atoi(argv[++i]);
        } else if (strcmp(argv[i], "--jitter-only") == 0) {
            jitterOnly = true;
        } else if (strcmp(argv[i], "--help") == 0 || strcmp(argv[i], "-h") == 0) {
            printf("Usage: %s [options]\n", argv[0]);
            printf("  --cycle-us <us>       PLC cycle (us, default 1000)\n");
            printf("  --diag-interval <s>   Diagnostics interval (s, default 5)\n");
            printf("  --jitter-only         Timer jitter test only\n");
            printf("\nNote: desktop timing relies on OS, ~100-500us jitter at 1ms\n");
            return 0;
        }
    }

    std::signal(SIGINT, signalHandler);
    std::signal(SIGTERM, signalHandler);

    if (!jitterOnly) plcInit();
    else RT_LOG_INFO("Jitter-only mode\n");

#ifdef ENABLE_DEBUG
    debugEngine.init(st2c_debug_vars, st2c_debug_var_count, st2c_build_id);
    debugEngine.bindMemory(&sched.gvl, &sched.image);
    sched.setDebugEngine(&debugEngine);
    int debugPort = 9090;
    if (debugTcpServerStart(debugEngine, debugPort)) {
        platform::logInfo("[Debug] TCP server on 127.0.0.1:%d\n", debugPort);
    }
#endif

    jitterReset(cycleUs);
    int64_t lastDiag = 0;
    uint64_t tickCount = 0;

    while (running) {
        int64_t now = platform::steadyUs();

        if (!jitterOnly) {
            plcTick();
            tickCount++;
        }

        jitterSample(now);

        int64_t next = now + cycleUs;
        int64_t sleepUs = next - platform::steadyUs();
        if (sleepUs > 0) platform::sleepUs(sleepUs);

        now = platform::steadyUs();
        if (now - lastDiag > (int64_t)diagIntervalS * 1000000) {
            lastDiag = now;
            if (jitter.count > 0) {
                int64_t avg = jitter.sumJitter / (int64_t)jitter.count;
                double variance = jitter.count > 1
                    ? (double)jitter.sumSquareJitter / jitter.count - (double)avg * avg
                    : 0;
                platform::logInfo("[DIAG] ticks=%llu  [JITTER] min=%lld max=%lld avg=%lld stddev=%lld (samples=%llu)\n",
                    (unsigned long long)tickCount,
                    (long long)jitter.minJitter, (long long)jitter.maxJitter,
                    (long long)avg,
                    (long long)(variance > 0 ? (int64_t)std::sqrt(variance) : 0),
                    (unsigned long long)jitter.count);
            }
        }
    }

    if (!jitterOnly) sched.stop();
#ifdef ENABLE_DEBUG
    debugTcpServerStop();
    platform::logInfo("[Debug] TCP server stopped\n");
#endif
    printJitterStats();
    platform::logInfo("Stopped. Total ticks: %llu\n", (unsigned long long)tickCount);
    return 0;
}
